import threading
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class Worker:
    id: str
    address: str
    max_concurrent: int = 4
    active_tasks: int = 0
    healthy: bool = True
    capabilities: list[str] = field(default_factory=list)

    @property
    def available(self) -> bool:
        return self.healthy and self.active_tasks < self.max_concurrent

    @property
    def load_fraction(self) -> float:
        return self.active_tasks / self.max_concurrent


class LeastConnectionsBalancer:
    def __init__(self) -> None:
        self._workers: dict[str, Worker] = {}
        self._lock = threading.Lock()

    def register(self, worker: Worker) -> None:
        with self._lock:
            self._workers[worker.id] = worker

    def deregister(self, worker_id: str) -> None:
        with self._lock:
            self._workers.pop(worker_id, None)

    def mark_healthy(self, worker_id: str, healthy: bool) -> None:
        with self._lock:
            if w := self._workers.get(worker_id):
                w.healthy = healthy

    def acquire(self, required_capabilities: list[str] = None) -> Optional[Worker]:
        """Select the least-loaded available worker. Thread-safe."""
        with self._lock:
            candidates = [
                w for w in self._workers.values()
                if w.available and (
                    not required_capabilities
                    or all(c in w.capabilities for c in required_capabilities)
                )
            ]
            if not candidates:
                return None
            # Least connections: pick worker with fewest active tasks
            chosen = min(candidates, key=lambda w: w.active_tasks)
            chosen.active_tasks += 1
            return chosen

    def release(self, worker_id: str) -> None:
        """Called when a task completes or fails on the worker."""
        with self._lock:
            if w := self._workers.get(worker_id):
                w.active_tasks = max(0, w.active_tasks - 1)


# --- Usage ---
balancer = LeastConnectionsBalancer()
balancer.register(Worker("w1", "http://agent-1:8000", capabilities=["search", "code"]))
balancer.register(Worker("w2", "http://agent-2:8000", capabilities=["search"]))
balancer.register(Worker("w3", "http://agent-3:8000", capabilities=["code", "vision"]))

worker = balancer.acquire(required_capabilities=["code"])
if worker:
    try:
        # dispatch task to worker.address
        print(f"Dispatching to {worker.id} (active: {worker.active_tasks})")
    finally:
        balancer.release(worker.id)

import json
import time
import threading
import redis


HEARTBEAT_TTL = 15  # seconds — worker must renew within this window
HEARTBEAT_INTERVAL = 5  # seconds — worker publishes every N seconds
WORKER_PREFIX = "agent:worker:"


class RedisWorker:
    """Run inside an agent worker process."""

    def __init__(self, worker_id: str, address: str, capabilities: list[str],
                 max_concurrent: int, redis_url: str = "redis://localhost:6379") -> None:
        self.id = worker_id
        self.r = redis.from_url(redis_url)
        self._meta = {
            "id": worker_id,
            "address": address,
            "capabilities": capabilities,
            "max_concurrent": max_concurrent,
        }
        self._stop = threading.Event()

    def start(self) -> None:
        """Register and begin heartbeating."""
        self._publish_heartbeat()
        t = threading.Thread(target=self._heartbeat_loop, daemon=True)
        t.start()

    def _publish_heartbeat(self) -> None:
        key = f"{WORKER_PREFIX}{self.id}"
        self.r.set(key, json.dumps(self._meta), ex=HEARTBEAT_TTL)

    def _heartbeat_loop(self) -> None:
        while not self._stop.wait(HEARTBEAT_INTERVAL):
            self._publish_heartbeat()

    def stop(self) -> None:
        self._stop.set()
        # Signal draining: remove the heartbeat key immediately
        self.r.delete(f"{WORKER_PREFIX}{self.id}")
        # Also remove active-task counter
        self.r.delete(f"{WORKER_PREFIX}{self.id}:active")

    def increment_active(self) -> int:
        return self.r.incr(f"{WORKER_PREFIX}{self.id}:active")

    def decrement_active(self) -> int:
        return self.r.decr(f"{WORKER_PREFIX}{self.id}:active")


class RedisBalancer:
    """Run as a separate dispatcher process."""

    def __init__(self, redis_url: str = "redis://localhost:6379") -> None:
        self.r = redis.from_url(redis_url)

    def _live_workers(self) -> list[dict]:
        keys = self.r.keys(f"{WORKER_PREFIX}*")
        # Filter out :active counter keys
        meta_keys = [k for k in keys if not k.endswith(b":active")]
        workers = []
        for k in meta_keys:
            raw = self.r.get(k)
            if raw:
                workers.append(json.loads(raw))
        return workers

    def _active_count(self, worker_id: str) -> int:
        val = self.r.get(f"{WORKER_PREFIX}{worker_id}:active")
        return int(val) if val else 0

    def pick(self, required_capabilities: list[str] = None) -> dict | None:
        workers = self._live_workers()
        if required_capabilities:
            workers = [
                w for w in workers
                if all(c in w["capabilities"] for c in required_capabilities)
            ]
        if not workers:
            return None
        # Sort by active task count ascending (least connections)
        workers.sort(key=lambda w: self._active_count(w["id"]))
        return workers[0]


# Worker process startup
worker = RedisWorker(
    worker_id="agent-3",
    address="http://agent-3:8000",
    capabilities=["code", "search"],
    max_concurrent=4,
)
worker.start()
print("Worker registered and heartbeating")

# Balancer dispatch
balancer = RedisBalancer()
chosen = balancer.pick(required_capabilities=["code"])
if chosen:
    print(f"Route task to: {chosen['address']}")
else:
    print("No available workers with 'code' capability")

from dataclasses import dataclass
from typing import Literal


@dataclass
class ContractTask:
    contract_id: str
    stage: Literal["extraction", "classification", "risk"]
    size_pages: int

    @property
    def required_capabilities(self) -> list[str]:
        caps = [self.stage]
        if self.stage == "risk" and self.size_pages > 100:
            caps.append("high_context")
        return caps


class ContractBalancer(LeastConnectionsBalancer):
    def dispatch(self, task: ContractTask) -> str:
        """Returns the worker address for the task, or raises if no worker available."""
        worker = self.acquire(required_capabilities=task.required_capabilities)
        if worker is None:
            raise RuntimeError(
                f"No available worker for stage={task.stage} "
                f"caps={task.required_capabilities}"
            )
        try:
            return worker.address
        except Exception:
            self.release(worker.id)
            raise


# Workers registered at startup
balancer = ContractBalancer()
for i in range(3):
    balancer.register(Worker(
        f"extraction-{i}", f"http://extract-{i}:8000",
        capabilities=["extraction"], max_concurrent=6
    ))
for i in range(4):
    balancer.register(Worker(
        f"risk-{i}", f"http://risk-{i}:8000",
        capabilities=["risk"], max_concurrent=3
    ))
# High-context risk agents for large contracts
for i in range(2):
    balancer.register(Worker(
        f"risk-hc-{i}", f"http://risk-hc-{i}:8000",
        capabilities=["risk", "high_context"], max_concurrent=2
    ))

task = ContractTask("contract-001", stage="risk", size_pages=250)
addr = balancer.dispatch(task)
print(f"Routing 250-page contract risk stage to: {addr}")
# => routes to a high_context worker only
